{
  "summary": "The paper introduces AmbiBench, a benchmark designed to study task ambiguity in language models and humans, focusing on how instructions and examples help disambiguate tasks. It empirically evaluates various large language models, highlighting the benefits of RLHF training and ambiguity-focused finetuning for improving ambiguity resolution. The work sheds light on challenges and strategies for robust task understanding under ambiguous specifications.",
  "strengths": [
    {
      "point": "Introduction of a novel benchmark targeting task ambiguity distinct from input ambiguity",
      "evidence": "AmbiBench consists of controlled binary classification tasks designed to induce ambiguity in task specification rather than input noise."
    },
    {
      "point": "Comprehensive empirical evaluation across multiple large language models and humans",
      "evidence": "The paper evaluates models with and without RLHF, varying prompt formats, and human baselines under different instruction and example conditions."
    },
    {
      "point": "Identification of RLHF and ambiguity-focused finetuning as effective strategies for resolving task ambiguity",
      "evidence": "Results show that the largest RLHF-trained model approaches or exceeds human performance, and finetuning on ambiguous examples improves standard models significantly."
    },
    {
      "point": "Clear problem motivation emphasizing real-world relevance of task ambiguity",
      "evidence": "The paper motivates the study by highlighting risks of misunderstanding in complex domains like programming and verification."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient positioning relative to prior work on ambiguity and instruction-following benchmarks",
      "evidence": "The paper omits comparison to datasets like FLAN and Super-NaturalInstructions and meta-learning approaches addressing task inference ambiguity."
    },
    {
      "point": "Limited task diversity and lack of justification for task selection",
      "evidence": "AmbiBench includes only six simple binary classification tasks without discussion on representing broader real-world ambiguity."
    },
    {
      "point": "Ambiguity construction lacks empirical or qualitative validation",
      "evidence": "No ablation studies or human qualitative feedback confirm that paired features induce genuine task ambiguity rather than label noise."
    },
    {
      "point": "RLHF vs. non-RLHF model comparisons are not controlled for model scale",
      "evidence": "No experiments isolate the effects of scale versus RLHF, limiting interpretability of performance differences."
    },
    {
      "point": "Prompt format sensitivity is underexplored and limited to a single model",
      "evidence": "Only T0++ is tested for prompt format effects, without systematic analysis across models."
    },
    {
      "point": "Human baseline evaluation lacks critical methodological details",
      "evidence": "Participant demographics, instructions, annotator counts, and quality controls are not reported."
    },
    {
      "point": "Evaluation relies primarily on accuracy, missing deeper analyses",
      "evidence": "No metrics on confidence calibration, consistency, or detailed error analysis are provided."
    },
    {
      "point": "No qualitative error analysis or human-model agreement assessment",
      "evidence": "The paper does not analyze common failure modes or where humans and models differ in ambiguity perception."
    },
    {
      "point": "No analysis of joint integration of instructions and examples",
      "evidence": "Models are tested separately on instructions or examples, without studying their combined effect."
    },
    {
      "point": "Reproducibility is hindered by missing finetuning details and lack of public release",
      "evidence": "Key finetuning hyperparameters, dataset composition, and code or data release are absent."
    },
    {
      "point": "Clarity of ambiguity definition and distinction from related concepts could be improved",
      "evidence": "Conceptual framing lacks precise definitions and illustrative examples."
    },
    {
      "point": "Benchmark does not capture complexities of real-world ambiguity",
      "evidence": "Tasks are single-turn, binary classification, ignoring multi-turn dialogue, multimodal inputs, or evolving goals."
    },
    {
      "point": "Safety and error implications are not analyzed despite motivation",
      "evidence": "No discussion on error types or risks of unsafe behavior resulting from ambiguity resolution failures."
    },
    {
      "point": "Limited model diversity and language scope restrict generalizability",
      "evidence": "Evaluation focuses on a narrow set of large English language models, excluding smaller, encoder-only, or non-English models."
    },
    {
      "point": "Finetuning improvements lack cross-domain validation",
      "evidence": "No experiments test whether finetuning gains transfer beyond AmbiBench."
    },
    {
      "point": "Presentation of results could be enhanced with more comprehensive visualizations",
      "evidence": "Key findings are described mainly in text without detailed tables or figures."
    },
    {
      "point": "No discussion of computational efficiency or cost trade-offs",
      "evidence": "The paper omits analysis of resource requirements for RLHF, finetuning, and baseline models."
    },
    {
      "point": "No exploration of ambiguity resolution in interactive or multi-turn settings",
      "evidence": "Experiments are limited to single-turn classification tasks without considering dialogue or interaction."
    }
  ],
  "questions": [
    {
      "question": "How does AmbiBench compare empirically and conceptually to existing instruction-following and meta-learning benchmarks addressing task ambiguity?",
      "motivation": "Clarifying this would strengthen the novelty claim and situate the work within the broader research landscape."
    },
    {
      "question": "Can the finetuning approach on ambiguous examples generalize to more complex, multi-class, or multimodal tasks beyond the current simple binary classification setting?",
      "motivation": "Understanding generalizability is crucial for practical applicability of the proposed training strategy."
    },
    {
      "question": "What are the effects of combining instructions and examples jointly for ambiguity resolution in models?",
      "motivation": "Real-world task specifications often include both, so studying their interaction would provide deeper insights."
    },
    {
      "question": "How robust are the human baseline results given the lack of methodological details, and how might variability in human judgments affect model comparisons?",
      "motivation": "Reliable human baselines are essential for contextualizing model performance."
    },
    {
      "question": "What are the computational costs and efficiency trade-offs of using large RLHF models versus finetuned standard models for ambiguity resolution?",
      "motivation": "This information is important for practical deployment considerations."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
